function wpbp_zero_price_products(): WP_Query {
    return new WP_Query( array(
        'post_type'      => 'product',
        'post_status'    => 'publish',
        'fields'         => 'ids',
        'meta_query'     => array(
            array(
                'key'     => 'price_cents',
                'value'   => 0,
                'compare' => '=',
                'type'    => 'NUMERIC',
            ),
        ),
    ) );
}
